// Definitive proof: rebuild real-cloud-captured cmd=8 frames with our builder
// and assert byte-for-byte equality (incl. CRC). Hex from the MITM capture
// (server .data/captures/mitm-2026-05-16T19-05-30-946Z.log, device 99999998).
import { buildLongMgmtFrame, parseMgmtFrame } from "../lib/protocol";

const CAPTURED: Record<string, string> = {
  "read1-big":
    "",
  "read1-small":
    "7e5a00013030303030303030303030300d323035353933323739343831353039303639300899999998300041542b454e434f4445484558534d533f0d41542b484558534d533f0d41542b44454255473f0d41542b53455248433f0deab57e",
  "read2-big":
    "",
  "read2-small":
    "7e5a00013030303030303030303030300d323035353933323833373739343132333737380899999998300041542b454e434f4445484558534d533f0d41542b484558534d533f0d41542b44454255473f0d41542b53455248433f0dbb577e",
};

let allOk = true;
for (const [name, hex] of Object.entries(CAPTURED)) {
  const cap = Buffer.from(hex, "hex");
  const p: any = parseMgmtFrame(cap);
  if (!p || p.kind !== "long") { console.log(`${name}: PARSE FAILED`); allOk = false; continue; }
  const customerId = cap.subarray(4, 16).toString("ascii");
  const resv4 = cap.subarray(32, 36); // inner[29..32]
  const rebuilt = buildLongMgmtFrame(p.atText, {
    customerId,
    msgSeq: p.msgSeq,
    cmd: p.cmd,
    deviceCode: p.manaId,
    resv4,
  });
  const eq = rebuilt.equals(cap);
  if (!eq) allOk = false;
  console.log(
    `${name}: ${eq ? "EXACT MATCH ✓" : "MISMATCH ✗"}  ` +
    `(cmd=${p.cmd} mana=${p.manaId} seq=${p.msgSeq} resv4="${resv4.toString("ascii")}" ` +
    `plen=${cap.readUInt16LE(41)} atLen=${Buffer.from(p.atText, "ascii").length} wire=${cap.length})`,
  );
  if (!eq) {
    for (let i = 0; i < Math.max(rebuilt.length, cap.length); i++) {
      if (rebuilt[i] !== cap[i]) {
        console.log(`  first diff @${i}: ours=0x${(rebuilt[i] ?? -1).toString(16)} cap=0x${(cap[i] ?? -1).toString(16)}`);
        break;
      }
    }
  }
}
console.log(allOk ? "\nALL FRAMES BYTE-EXACT — builder == real Four-Faith cloud ✓" : "\nFAILURES PRESENT ✗");
process.exit(allOk ? 0 : 1);
